    ```java
import java.util.*;

class UndergroundSystem {
    private Map<Integer, Pair<String, Integer>> checkInInfo;
    private Map<String, Pair<Integer, Integer>> journeyData;

    public UndergroundSystem() {
        checkInInfo = new HashMap<>();
        journeyData = new HashMap<>();
    }

    public void checkIn(int id, String stationName, int t) {
        checkInInfo.put(id, new Pair<>(stationName, t));
    }

    public void checkOut(int id, String stationName, int t) {
        Pair<String, Integer> startInfo = checkInInfo.get(id);
        String route = startInfo.getKey() + "_" + stationName;
        int duration = t - startInfo.getValue();
        Pair<Integer, Integer> data = journeyData.getOrDefault(route, new Pair<>(0, 0));
        journeyData.put(route, new Pair<>(data.getKey() + duration, data.getValue() + 1));
    }

    public double getAverageTime(String startStation, String endStation) {
        String route = startStation + "_" + endStation;
        Pair<Integer, Integer> data = journeyData.get(route);
        return (double) data.getKey() / data.getValue();
    }
}
```

